#!/bin/bash
sed -i '' 's/fun getKPSignificatorsForPlanet.*/fun applyKBACancellation(houses: List<Int>): List<Int> {\n    val result = houses.toMutableSet()\n    val toRemove = mutableSetOf<Int>()\n    for (h1 in result) {\n        for (h2 in result) {\n            if (h1 == h2) continue\n            val twelfthFromH2 = if (h2 == 1) 12 else h2 - 1\n            if (h1 == twelfthFromH2) {\n                toRemove.add(h2)\n            }\n        }\n    }\n    result.removeAll(toRemove)\n    return result.sorted()\n}\n\nfun getKBAPlanetConnections(planetName: String, data: ChartData): String {\n    val planet = data.planets.find { it.name.equals(planetName, ignoreCase = true) } ?: return ""\n    val starLordName = planet.starLord ?: ""\n    val starLordPlanet = data.planets.find { it.name.equals(starLordName, ignoreCase = true) }\n    val houses = mutableListOf<Int>()\n    houses.add(planet.house)\n    if (starLordPlanet != null) houses.add(starLordPlanet.house)\n    return applyKBACancellation(houses).joinToString(",")\n}\n\nfun getKBAHouseConnections(houseIndex: Int, data: ChartData): String {\n    val house = data.houses.details.getOrNull(houseIndex) ?: return ""\n    val starLordName = house.starLord ?: ""\n    val starLordPlanet = data.planets.find { it.name.equals(starLordName, ignoreCase = true) } ?: return ""\n    val ssName = starLordPlanet.starLord ?: ""\n    val ssPlanet = data.planets.find { it.name.equals(ssName, ignoreCase = true) }\n    val houses = mutableListOf<Int>()\n    houses.add(starLordPlanet.house)\n    if (ssPlanet != null) houses.add(ssPlanet.house)\n    return applyKBACancellation(houses).joinToString(",")\n}\n\nfun oldGetKP/g' /Users/wohozo/Documents/Astro Eleven/astroeleven/android/app/src/main/java/com/astroeleven/user/ui/chart/VipChartActivity.kt
